import Slider from "react-slick";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import React, { useEffect, useRef, useState } from 'react';


const PartnersCarousel = () => {
    const containerRef = useRef(null);
    const [isContainerVisible, setIsContainerVisible] = useState(false);


    useEffect(() => {
        const observer = new IntersectionObserver(
            ([entry]) => {
                if (entry.isIntersecting) {
                    setIsContainerVisible(true);
                    observer.disconnect();
                }
            },
            { threshold: 0.1 }
        );

        if (containerRef.current) {
            observer.observe(containerRef.current);
        }

        return () => observer.disconnect();
    }, []);

    const settings = {
        className: "center",
        centerMode: true,

        // Drag & swipe
        draggable: true,
        swipe: true,
        touchMove: true,
        swipeToSlide: true,
        swipeThreshold: 10,
        touchThreshold: 10,

        // Pagination & arrows
        dots: false,       // remove the duplicate
        arrows: true,
        infinite: true,

        // Animation & autoplay (use reasonable values)
        speed: 500,        // 500 ms per slide transition
        autoplay: true,
        autoplaySpeed: 3000, // 3 seconds between auto-advances
        cssEase: "linear",

        slidesToShow: 4,
        slidesToScroll: 1,

        responsive: [
            { breakpoint: 1200, settings: { slidesToShow: 4 } },
            { breakpoint: 800, settings: { slidesToShow: 1 } },
            { breakpoint: 600, settings: { slidesToShow: 1 } },
            { breakpoint: 500, settings: { slidesToShow: 1 } }
        ]
    };

    const logos = [
        'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcT8rDzenLjCgJHrEgfBZksBhPlUP7Y8oqdEJg&s',
        'data:image/png;base64,',
        'data:image/png;base64,',
        'data:image/png;base64,',
        'data:image/png;base64,',
        'data:image/jpeg;base64,',
        'data:image/png;base64,',
        'data:image/png;base64,',
        'data:image/jpeg;base64,',
        'data:image/png;base64,',
        'data:image/png;base64,',
        'data:image/png;base64,',
        'data:image/jpeg;base64,',
        'data:image/png;base64,',
        'data:image/png;base64,',
        'data:image/png;base64,'
    ];

    return (
        <section className="py-5 mb-5 custom-bg" id="partner-section">
            <div ref={containerRef} className={`container ${isContainerVisible ? 'slide-in-y' : 'slide-out-y'}`}>
                <h1 className="text-center golden-text pb-5">Our Partners</h1>
                <Slider {...settings} className="partner-slider">
                    {logos.map((src, index) => (
                        <div key={index} className="slide-item">
                            <img src={src} alt="client logo" className="client-img" />
                        </div>
                    ))}
                </Slider>

                

            </div>
        </section>
    )
};

export default PartnersCarousel;
